// Edit LOCAL_STATES to change the monitored region
const LOCAL_STATES = ['Texas','TX','Oklahoma','OK','Louisiana','LA','New Mexico','NM','Arkansas','AR'];
const isLocal = t => t && LOCAL_STATES.some(s => t.includes(s));

// Fingerprint each response by its unique shape
let weatherRaw, quakeRaw, fireRaw, femaRaw, spcRaw, airRaw, gaugeRaw;
for (const item of $input.all()) {
  const j = item.json;
  if (j['@context'] && j.features)                                        weatherRaw = j;
  else if (j.features && j.metadata?.url?.includes('usgs'))               quakeRaw   = j;
  else if (j.features && j.features[0]?.properties?.LABEL !== undefined)  spcRaw     = j;
  else if (j.features)                                                     fireRaw    = j;
  else if (j.DisasterDeclarationsSummaries !== undefined)                  femaRaw    = j;
  else if (Array.isArray(j) || Array.isArray(item.json[0]?.AQI !== undefined ? j : null)) airRaw = Array.isArray(j) ? j : null;
  else if (j.value?.timeSeries !== undefined)                              gaugeRaw   = j;
}
// AirNow returns a top-level array — handle that case
if (!airRaw) {
  for (const item of $input.all()) {
    if (Array.isArray(item.json) && item.json[0]?.AQI !== undefined) { airRaw = item.json; break; }
  }
}

// ── WEATHER (NWS — already TX-scoped) ────────────────────────────
const weather = (weatherRaw?.features ?? []).map(f => ({
  event: f.properties?.event, severity: f.properties?.severity,
  urgency: f.properties?.urgency, area: f.properties?.areaDesc,
  headline: f.properties?.headline, expires: f.properties?.expires
}));

// ── EARTHQUAKES (USGS — filter to local) ─────────────────────────
const quakes = (quakeRaw?.features ?? [])
  .map(f => ({
    magnitude: f.properties?.mag, place: f.properties?.place,
    time: f.properties?.time ? new Date(f.properties.time).toISOString() : null,
    tsunami: f.properties?.tsunami === 1, alert: f.properties?.alert,
    depth_km: f.geometry?.coordinates?.[2]
  }))
  .filter(q => isLocal(q.place));

// ── WILDFIRES (NIFC — filter to local) ───────────────────────────
const fires = (fireRaw?.features ?? [])
  .map(f => ({
    name: f.properties?.IncidentName, state: f.properties?.POOState,
    county: f.properties?.POOCounty, acres: f.properties?.DailyAcres,
    percentContained: f.properties?.PercentContained
  }))
  .filter(f => isLocal(f.state));

// ── FEMA (filter to local) ────────────────────────────────────────
const fema = (femaRaw?.DisasterDeclarationsSummaries ?? [])
  .filter(d => isLocal(d.state))
  .map(d => ({
    id: d.disasterNumber, title: d.declarationTitle,
    state: d.state, type: d.incidentType, declared: d.declarationDate
  }));

// ── SPC OUTLOOK (keep only elevated+ risk categories) ────────────
const SPC_ELEVATED = ['TSTM','MRGL','SLGT','ENH','MDT','HIGH'];
const spc = (spcRaw?.features ?? [])
  .filter(f => SPC_ELEVATED.includes(f.properties?.LABEL))
  .map(f => ({
    category: f.properties?.LABEL,
    categoryName: f.properties?.LABEL2,
    fill: f.properties?.fill
  }));

// ── AIRNOW AQI (keep only Unhealthy for Sensitive+ readings) ─────
const aqi = (airRaw ?? [])
  .filter(r => (r.AQI ?? 0) >= 101)
  .map(r => ({
    area: r.ReportingArea, state: r.StateCode,
    aqi: r.AQI, category: r.Category?.Name,
    pollutant: r.ParameterName
  }));

// ── USGS STREAM GAUGES (above flood stage = stage > 0 action) ────
// The IV service returns timeSeries array; each has siteCode + values
const gauges = (gaugeRaw?.value?.timeSeries ?? [])
  .map(ts => ({
    site: ts.sourceInfo?.siteName,
    siteCode: ts.sourceInfo?.siteCode?.[0]?.value,
    latestStage_ft: parseFloat(ts.values?.[0]?.value?.[0]?.value ?? 'NaN'),
    dateTime: ts.values?.[0]?.value?.[0]?.dateTime ?? null
  }))
  .filter(g => !isNaN(g.latestStage_ft) && g.latestStage_ft > 15);
// Note: 15 ft is a rough proxy — real flood stage varies per gauge.
// For production, cross-reference USGS flood-stage thresholds per site.

return [{ json: { generatedAt: new Date().toISOString(), weather, quakes, fires, fema, spcOutlook: spc, airQuality: aqi, streamGauges: gauges } }];
